import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import SwipeableCard from './components/SwipeableCard';
import Sidebar from './components/Sidebar';
import InvestedCompanies from './components/InvestedCompanies';
import './App.css';

// Main Swiping Interface Component
const SwipingInterface = () => {
  const [companies, setCompanies] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [likedCompanies, setLikedCompanies] = useState([]);
  const [passedCompanies, setPassedCompanies] = useState([]);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [moneyBalance, setMoneyBalance] = useState(50000000);
  const [showInvestmentAnimation, setShowInvestmentAnimation] = useState(false);

  useEffect(() => {
    // Load saved swipe data from localStorage
    const savedLikedCompanies = localStorage.getItem('ycSwipe_likedCompanies');
    const savedPassedCompanies = localStorage.getItem('ycSwipe_passedCompanies');
    const savedCurrentIndex = localStorage.getItem('ycSwipe_currentIndex');
    const savedMoneyBalance = localStorage.getItem('ycSwipe_moneyBalance');
    
    if (savedLikedCompanies) {
      setLikedCompanies(JSON.parse(savedLikedCompanies));
    }
    if (savedPassedCompanies) {
      setPassedCompanies(JSON.parse(savedPassedCompanies));
    }
    if (savedCurrentIndex) {
      setCurrentIndex(parseInt(savedCurrentIndex));
    }
    if (savedMoneyBalance) {
      setMoneyBalance(parseInt(savedMoneyBalance));
    }

    // Load companies data
    fetch('/all.json')
      .then(response => response.json())
      .then(data => {
        // Filter out companies without essential data
        const validCompanies = data.filter(company => 
          company.name && 
          company.one_liner && 
          company.long_description
        );
        
        // Randomize the companies list using Fisher-Yates shuffle
        const shuffledCompanies = [...validCompanies];
        for (let i = shuffledCompanies.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [shuffledCompanies[i], shuffledCompanies[j]] = [shuffledCompanies[j], shuffledCompanies[i]];
        }
        
        setCompanies(shuffledCompanies);
      })
      .catch(error => {
        console.error('Error loading companies:', error);
      });
  }, []);

  const handleSwipe = (direction) => {
    const currentCompany = companies[currentIndex];
    
    if (direction === 'right') {
      const newLikedCompanies = [...likedCompanies, currentCompany];
      setLikedCompanies(newLikedCompanies);
      localStorage.setItem('ycSwipe_likedCompanies', JSON.stringify(newLikedCompanies));
      
      // Deduct investment amount
      const newBalance = moneyBalance - 5000;
      setMoneyBalance(newBalance);
      localStorage.setItem('ycSwipe_moneyBalance', newBalance.toString());
      
      // Trigger investment animation
      console.log('Triggering investment animation');
      setShowInvestmentAnimation(true);
      setTimeout(() => {
        console.log('Hiding investment animation');
        setShowInvestmentAnimation(false);
      }, 2000);
    } else {
      const newPassedCompanies = [...passedCompanies, currentCompany];
      setPassedCompanies(newPassedCompanies);
      localStorage.setItem('ycSwipe_passedCompanies', JSON.stringify(newPassedCompanies));
    }
    
    const newIndex = currentIndex + 1;
    setCurrentIndex(newIndex);
    localStorage.setItem('ycSwipe_currentIndex', newIndex.toString());
  };


  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  const closeSidebar = () => {
    setSidebarOpen(false);
  };

  const resetApp = () => {
    setCurrentIndex(0);
    setLikedCompanies([]);
    setPassedCompanies([]);
    setSidebarOpen(false);
    setMoneyBalance(50000000);
    setShowInvestmentAnimation(false);
    
    // Clear localStorage data
    localStorage.removeItem('ycSwipe_likedCompanies');
    localStorage.removeItem('ycSwipe_passedCompanies');
    localStorage.removeItem('ycSwipe_currentIndex');
    localStorage.removeItem('ycSwipe_moneyBalance');
  };

  if (companies.length === 0) {
    return (
      <div className="loading">
        <div className="loading-spinner"></div>
        <p>Loading YC companies...</p>
      </div>
    );
  }

  if (currentIndex >= companies.length) {
    return (
      <div className="end-screen">
        <h1>🎉 All Done!</h1>
        <div className="stats">
          <div className="stat">
            <h2>{likedCompanies.length}</h2>
            <p>Liked</p>
          </div>
          <div className="stat">
            <h2>{passedCompanies.length}</h2>
            <p>Passed</p>
          </div>
        </div>
        <button className="reset-btn" onClick={resetApp}>
          Start Over
        </button>
      </div>
    );
  }

  return (
    <div className="app">
      <div className="header">
        <div className="header-top">
          <button className="burger-menu" onClick={toggleSidebar}>
            <span></span>
            <span></span>
            <span></span>
          </button>
          <h1 className="app-title">SwipeVC</h1>
          <div className="money-display">
            <span className="money-symbol">💰</span>
            <span className="money-amount">${moneyBalance.toLocaleString()}</span>
            {showInvestmentAnimation && (
              <div className="investment-animation">
                -$5,000
              </div>
            )}
          </div>
        </div>
        <div className="swipe-directions">
          <div className="swipe-left-indicator">👈 Pass</div>
          <div className="swipe-right-indicator">Invest 👉</div>
        </div>

      </div>
      
      <div className="card-container">
        <SwipeableCard
          company={companies[currentIndex]}
          onSwipe={handleSwipe}
        />
      </div>

      <Sidebar 
        isOpen={sidebarOpen}
        onClose={closeSidebar}
        likedCompanies={likedCompanies}
        onReset={resetApp}
      />
    </div>
  );
};

// Main App Component with Routing
function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<SwipingInterface />} />
        <Route path="/invested" element={<div className="app invested-page"><InvestedCompanies /></div>} />
      </Routes>
    </Router>
  );
}

export default App;
