import React, { useRef, useEffect } from 'react';
import { useSpring, animated } from 'react-spring';
import { useSwipeable } from 'react-swipeable';
import './SwipeableCard.css';

const SwipeableCard = ({ company, onSwipe }) => {
  const cardRef = useRef(null);

  const [{ x, y, scale, rotate }, api] = useSpring(() => ({
    x: 0,
    y: 0,
    scale: 1,
    rotate: 0,
    config: { tension: 300, friction: 30 }
  }));

  const handleSwipeStart = (eventData) => {
    // Optional: Add any visual feedback when swipe starts
  };

  const handleSwiping = (eventData) => {
    const deltaX = eventData.deltaX;
    const deltaY = eventData.deltaY;
    
    // Only respond to horizontal swipes, ignore vertical scrolling
    if (Math.abs(deltaX) > Math.abs(deltaY)) {
      // Make movement more responsive with higher multiplier
      api.start({
        x: deltaX * 1.2,
        y: deltaX * 0.05,
        scale: 1.05,
        rotate: deltaX * 0.15,
      });
    }
  };

  const handleSwipeEnd = (eventData) => {
    const deltaX = eventData.deltaX;
    const deltaY = eventData.deltaY;
    const velocity = Math.abs(eventData.velocity);
    const threshold = 120; // Increased threshold for more intentional swipes
    
    // Only trigger swipe if it's clearly a horizontal gesture
    if (Math.abs(deltaX) > Math.abs(deltaY) && (Math.abs(deltaX) > threshold || velocity > 0.8)) {
      const direction = deltaX > 0 ? 'right' : 'left';
      
      // Animate card off screen before calling onSwipe
      api.start({
        x: direction === 'right' ? 1000 : -1000,
        y: direction === 'right' ? 200 : -200,
        scale: 0.8,
        rotate: direction === 'right' ? 30 : -30,
        config: { tension: 300, friction: 30 }
      });
      
      // Call onSwipe after a short delay to allow animation
      setTimeout(() => {
        onSwipe(direction);
        // Reset position for next card
        api.start({
          x: 0,
          y: 0,
          scale: 1,
          rotate: 0,
        });
      }, 200);
    } else {
      // Snap back to center with smooth animation
      api.start({
        x: 0,
        y: 0,
        scale: 1,
        rotate: 0,
        config: { tension: 300, friction: 30 }
      });
    }
  };

  // Configure the swipeable behavior
  const swipeHandlers = useSwipeable({
    onSwiping: handleSwiping,
    onSwipeStart: handleSwipeStart,
    onSwiped: handleSwipeEnd,
    trackMouse: true, // Enable mouse dragging
    preventDefaultTouchmoveEvent: false, // Allow normal scrolling
    delta: 50, // Increased minimum distance for a swipe
    trackTouch: true,
    rotationAngle: 0,
    swipeDuration: 500,
    touchEventOptions: { passive: false },
  });

  // Reset card position when company changes
  useEffect(() => {
    api.start({
      x: 0,
      y: 0,
      scale: 1,
      rotate: 0,
    });
  }, [company.id]);

  const formatDate = (timestamp) => {
    if (!timestamp) return 'Unknown';
    const date = new Date(timestamp * 1000);
    return date.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'long' 
    });
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'Active': return '#4CAF50';
      case 'Acquired': return '#2196F3';
      case 'Public': return '#FF9800';
      default: return '#9E9E9E';
    }
  };

  return (
    <animated.div
      ref={cardRef}
      className="swipeable-card"
      style={{
        x,
        y,
        scale,
        rotate: rotate.to(r => `${r}deg`),
      }}
      {...swipeHandlers}
    >
      <div className="card-header">
        <div className="company-logo">
          {company.small_logo_thumb_url ? (
            <img 
              src={company.small_logo_thumb_url} 
              alt={`${company.name} logo`}
              onError={(e) => {
                e.target.style.display = 'none';
              }}
            />
          ) : (
            <div className="logo-placeholder">
              {company.name.charAt(0)}
            </div>
          )}
        </div>
        <div className="company-basic-info">
          <h2 className="company-name">{company.name}</h2>
          <p className="one-liner">{company.one_liner}</p>
          <div className="status-badge" style={{ backgroundColor: getStatusColor(company.status) }}>
            {company.status}
          </div>
        </div>
      </div>

      <div className="card-content">
        <div className="description">
          <p>{company.long_description}</p>
        </div>

        <div className="company-details">
          <div className="detail-row">
            <span className="label">Batch:</span>
            <span className="value">{company.batch || 'Unknown'}</span>
          </div>
          
          <div className="detail-row">
            <span className="label">Industry:</span>
            <span className="value">{company.industry || 'Unknown'}</span>
          </div>
          
          <div className="detail-row">
            <span className="label">Location:</span>
            <span className="value">{company.all_locations || 'Unknown'}</span>
          </div>
          
          <div className="detail-row">
            <span className="label">Team Size:</span>
            <span className="value">{company.team_size || 'Unknown'}</span>
          </div>
          
          <div className="detail-row">
            <span className="label">Launched:</span>
            <span className="value">{formatDate(company.launched_at)}</span>
          </div>
        </div>

        {company.tags && company.tags.length > 0 && (
          <div className="tags">
            {company.tags.slice(0, 5).map((tag, index) => (
              <span key={index} className="tag">
                {tag}
              </span>
            ))}
          </div>
        )}

        {company.website && (
          <div className="website-link">
            <a 
              href={company.website} 
              target="_blank" 
              rel="noopener noreferrer"
              onClick={(e) => e.stopPropagation()}
            >
              Visit Website →
            </a>
          </div>
        )}
      </div>

    </animated.div>
  );
};

export default SwipeableCard;
