import React from 'react';
import { Link } from 'react-router-dom';
import './Sidebar.css';

const Sidebar = ({ isOpen, onClose, likedCompanies, onReset }) => {
  return (
    <>
      {/* Overlay */}
      {isOpen && <div className="sidebar-overlay" onClick={onClose}></div>}
      
      {/* Sidebar */}
      <div className={`sidebar ${isOpen ? 'sidebar-open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
          <button className="close-btn" onClick={onClose}>
            ✕
          </button>
        </div>
        
        <div className="sidebar-content">
          {/* Invested Companies Section */}
          <div className="sidebar-section">
            <div className="section-header">
              <h3>Invested Companies ({likedCompanies.length})</h3>
              <Link to="/invested" className="view-all-link" onClick={onClose}>
                View All →
              </Link>
            </div>
            <div className="invested-list">
              {likedCompanies.length === 0 ? (
                <p className="empty-state">No companies invested in yet</p>
              ) : (
                <div className="companies-list">
                  {likedCompanies.slice(0, 3).map((company, index) => (
                    <div key={company.id || index} className="company-item">
                      <div className="company-logo-small">
                        {company.small_logo_thumb_url ? (
                          <img 
                            src={company.small_logo_thumb_url} 
                            alt={`${company.name} logo`}
                            onError={(e) => {
                              e.target.style.display = 'none';
                            }}
                          />
                        ) : (
                          <div className="logo-placeholder-small">
                            {company.name.charAt(0)}
                          </div>
                        )}
                      </div>
                      <div className="company-info-small">
                        <h4>{company.name}</h4>
                        <p>{company.one_liner}</p>
                        <span className="status-badge-small" style={{ 
                          backgroundColor: getStatusColor(company.status) 
                        }}>
                          {company.status}
                        </span>
                      </div>
                    </div>
                  ))}
                  {likedCompanies.length > 3 && (
                    <div className="more-companies">
                      <Link to="/invested" className="view-more-link" onClick={onClose}>
                        +{likedCompanies.length - 3} more companies
                      </Link>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
          
          {/* Settings Section */}
          <div className="sidebar-section">
            <h3>Settings</h3>
            <div className="settings-content">
              <button className="reset-all-btn" onClick={onReset}>
                Reset All Data
              </button>
              <p className="reset-warning">
                This will clear all your invested companies and start over.
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

const getStatusColor = (status) => {
  switch (status) {
    case 'Active': return '#4CAF50';
    case 'Acquired': return '#2196F3';
    case 'Public': return '#FF9800';
    default: return '#9E9E9E';
  }
};

export default Sidebar;
