import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './InvestedCompanies.css';

const InvestedCompanies = () => {
  const [likedCompanies, setLikedCompanies] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterIndustry, setFilterIndustry] = useState('all');
  const [sortBy, setSortBy] = useState('name');

  useEffect(() => {
    // Load saved liked companies from localStorage
    const savedLikedCompanies = localStorage.getItem('ycSwipe_likedCompanies');
    if (savedLikedCompanies) {
      setLikedCompanies(JSON.parse(savedLikedCompanies));
    }
  }, []);

  const getStatusColor = (status) => {
    switch (status) {
      case 'Active': return '#4CAF50';
      case 'Acquired': return '#2196F3';
      case 'Public': return '#FF9800';
      default: return '#9E9E9E';
    }
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return 'Unknown';
    const date = new Date(timestamp * 1000);
    return date.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'long' 
    });
  };

  // Get unique industries for filter dropdown
  const industries = [...new Set(likedCompanies.map(company => company.industry).filter(Boolean))];

  // Filter and search companies
  const filteredCompanies = likedCompanies
    .filter(company => {
      const matchesSearch = company.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                           company.one_liner.toLowerCase().includes(searchTerm.toLowerCase()) ||
                           (company.tags && company.tags.some(tag => 
                             tag.toLowerCase().includes(searchTerm.toLowerCase())
                           ));
      
      const matchesStatus = filterStatus === 'all' || company.status === filterStatus;
      const matchesIndustry = filterIndustry === 'all' || company.industry === filterIndustry;
      
      return matchesSearch && matchesStatus && matchesIndustry;
    })
    .sort((a, b) => {
      switch (sortBy) {
        case 'name':
          return a.name.localeCompare(b.name);
        case 'status':
          return a.status.localeCompare(b.status);
        case 'industry':
          return (a.industry || '').localeCompare(b.industry || '');
        case 'launched':
          return (b.launched_at || 0) - (a.launched_at || 0);
        default:
          return 0;
      }
    });

  const totalInvestment = likedCompanies.length * 5000;

  return (
    <div className="invested-companies-page">
      <div className="page-header">
        <Link to="/" className="back-button">
          ← Back to Swiping
        </Link>
        <h1 className="page-title">My Investments</h1>
        <div className="investment-summary">
          <div className="summary-stat">
            <span className="stat-number">{likedCompanies.length}</span>
            <span className="stat-label">Companies</span>
          </div>
          <div className="summary-stat">
            <span className="stat-number">${totalInvestment.toLocaleString()}</span>
            <span className="stat-label">Invested</span>
          </div>
        </div>
      </div>

      <div className="search-and-filters">
        <div className="search-bar">
          <input
            type="text"
            placeholder="Search companies, descriptions, or tags..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-input"
          />
        </div>

        <div className="filters">
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="filter-select"
          >
            <option value="all">All Statuses</option>
            <option value="Active">Active</option>
            <option value="Acquired">Acquired</option>
            <option value="Public">Public</option>
          </select>

          <select
            value={filterIndustry}
            onChange={(e) => setFilterIndustry(e.target.value)}
            className="filter-select"
          >
            <option value="all">All Industries</option>
            {industries.map(industry => (
              <option key={industry} value={industry}>{industry}</option>
            ))}
          </select>

          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            className="filter-select"
          >
            <option value="name">Sort by Name</option>
            <option value="status">Sort by Status</option>
            <option value="industry">Sort by Industry</option>
            <option value="launched">Sort by Launch Date</option>
          </select>
        </div>
      </div>

      <div className="companies-list">
        {filteredCompanies.length === 0 ? (
          <div className="empty-state">
            {likedCompanies.length === 0 ? (
              <div>
                <h3>No investments yet</h3>
                <p>Start swiping to invest in companies!</p>
                <Link to="/" className="start-swiping-btn">
                  Start Swiping
                </Link>
              </div>
            ) : (
              <div>
                <h3>No companies match your search</h3>
                <p>Try adjusting your search terms or filters</p>
              </div>
            )}
          </div>
        ) : (
          filteredCompanies.map((company, index) => (
            <div key={company.id || index} className="company-item">
              <div className="company-logo-small">
                {company.small_logo_thumb_url ? (
                  <img 
                    src={company.small_logo_thumb_url} 
                    alt={`${company.name} logo`}
                    onError={(e) => {
                      e.target.style.display = 'none';
                    }}
                  />
                ) : (
                  <div className="logo-placeholder-small">
                    {company.name.charAt(0)}
                  </div>
                )}
              </div>
              <div className="company-info-small">
                <h4>{company.name}</h4>
                <p>{company.one_liner}</p>
                <div className="company-meta">
                  <span className="status-badge-small" style={{ 
                    backgroundColor: getStatusColor(company.status) 
                  }}>
                    {company.status}
                  </span>
                  <span className="investment-amount">$5,000</span>
                </div>
              </div>
              {company.website && (
                <a 
                  href={company.website} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="website-link-small"
                >
                  →
                </a>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default InvestedCompanies;
